WITH campaign_audiences AS (
  SELECT DISTINCT campaign_id, user_id, DATE_TRUNC('week', campaign_start_date) AS week_start FROM campaign_audience_mapping WHERE campaign_start_date BETWEEN {start_date} AND {end_date}
),
overlap_users AS (
  SELECT user_id, COUNT(DISTINCT campaign_id) AS campaign_count FROM campaign_audiences GROUP BY user_id HAVING COUNT(DISTINCT campaign_id) >= 2
),
total_users AS (
  SELECT COUNT(DISTINCT user_id) AS total_users FROM campaign_audiences
)
SELECT ou.user_count, tu.total_users, ou.user_count * 100.0 / NULLIF(tu.total_users, 0) AS overlap_rate FROM (SELECT COUNT(DISTINCT user_id) AS user_count FROM overlap_users) ou, total_users tu

WITH holdout_assignment AS (
  SELECT user_id, CASE WHEN campaign_exposure = true THEN 'treatment' ELSE 'control' END AS group FROM holdout_mapping hm WHERE hm.campaign_id = {campaign_id} AND hm.assignment_date BETWEEN {start_date} AND {end_date}
),
treatment_conversions AS (
  SELECT COUNT(DISTINCT CASE WHEN ha.group = 'treatment' THEN o.customer_id END) AS treatment_conversions FROM orders o JOIN holdout_assignment ha ON o.customer_id = ha.user_id WHERE o.status = 'completed' AND o.order_date BETWEEN {start_date} AND {end_date}
),
control_conversions AS (
  SELECT COUNT(DISTINCT CASE WHEN ha.group = 'control' THEN o.customer_id END) AS control_conversions FROM orders o JOIN holdout_assignment ha ON o.customer_id = ha.user_id WHERE o.status = 'completed' AND o.order_date BETWEEN {start_date} AND {end_date}
)
SELECT tc.treatment_conversions, cc.control_conversions, (tc.treatment_conversions - cc.control_conversions) * 100.0 / NULLIF(tc.treatment_conversions, 0) AS incrementality_pct FROM treatment_conversions tc, control_conversions cc

WITH landing_page_views AS (
  SELECT session_id, landing_page_url, campaign_id FROM session_events WHERE event_type = 'page_view' AND landing_page_url LIKE '%utm_campaign=%' AND event_date BETWEEN {start_date} AND {end_date}
),
conversions AS (
  SELECT DISTINCT session_id, campaign_id FROM orders o JOIN landing_page_views lpv ON o.session_id = lpv.session_id WHERE o.status = 'completed' AND o.order_date BETWEEN {start_date} AND {end_date}
),
landing_metrics AS (
  SELECT lpv.campaign_id, COUNT(DISTINCT lpv.session_id) AS landing_page_views, COUNT(DISTINCT c.session_id) AS conversions FROM landing_page_views lpv LEFT JOIN conversions c ON lpv.session_id = c.session_id AND lpv.campaign_id = c.campaign_id GROUP BY lpv.campaign_id
)
SELECT campaign_id, landing_page_views, conversions, conversions * 100.0 / NULLIF(landing_page_views, 0) AS conversion_rate FROM landing_metrics
